{"code": "import json
import scipy.stats as stats
import pandas as pd

# Read the clinical data file
clinical_data_file = var_functions.query_db:18
with open(clinical_data_file, 'r') as f:
    clinical_data = json.load(f)

# Read the mutation data file
mutation_data_file = var_functions.query_db:60
with open(mutation_data_file, 'r') as f:
    mutation_data = json.load(f)

# Extract participant barcodes and histological types from clinical data
patient_info = []
for record in clinical_data:
    desc = record.get('Patient_description', '')
    hist_type = record.get('histological_type', '')

    # Extract TCGA barcode using regex
    import re
    tcga_match = re.search(r'(TCGA-\w+-\w+)', desc)
    if tcga_match:
        barcode = tcga_match.group(1)
        # Only include patients with known histological types (exclude None/empty/"None")
        if hist_type and hist_type != 'None' and hist_type.strip():
            patient_info.append({
                'ParticipantBarcode': barcode,
                'histological_type': hist_type
            })

# Create a set of patients with CDH1 mutations (only reliable PASS filter)
cdh1_mutated_patients = set()
for record in mutation_data:
    if record['FILTER'] == 'PASS':
        cdh1_mutated_patients.add(record['ParticipantBarcode'])

# Build the contingency table
# Rows: histological types, Columns: CDH1 mutation status (Mutated, Not Mutated)
contingency_data = {}
for patient in patient_info:
    hist_type = patient['histological_type']
    barcode = patient['ParticipantBarcode']

    if hist_type not in contingency_data:
        contingency_data[hist_type] = {'mutated': 0, 'not_mutated': 0}

    if barcode in cdh1_mutated_patients:
        contingency_data[hist_type]['mutated'] += 1
    else:
        contingency_data[hist_type]['not_mutated'] += 1

# Filter out categories with marginal totals <= 10
filtered_data = {}
for hist_type, counts in contingency_data.items():
    row_total = counts['mutated'] + counts['not_mutated']
    if row_total > 10:
        filtered_data[hist_type] = counts

# Calculate marginal totals
col_totals = {'mutated': 0, 'not_mutated': 0}
row_totals = {}
grand_total = 0

for hist_type, counts in filtered_data.items():
    row_total = counts['mutated'] + counts['not_mutated']
    row_totals[hist_type] = row_total
    col_totals['mutated'] += counts['mutated']
    col_totals['not_mutated'] += counts['not_mutated']
    grand_total += row_total

# Calculate chi-square statistic
chi_square = 0
expected_freq = {}

for hist_type in filtered_data:
    expected_freq[hist_type] = {}
    for status in ['mutated', 'not_mutated']:
        # Expected frequency = (row_total * col_total) / grand_total
        expected = (row_totals[hist_type] * col_totals[status]) / grand_total
        expected_freq[hist_type][status] = expected

        # Chi-square component
        observed = filtered_data[hist_type][status]
        chi_square += ((observed - expected) ** 2) / expected

# Also calculate p-value using scipy
observed_matrix = []
for hist_type in filtered_data:
    observed_matrix.append([
        filtered_data[hist_type]['mutated'],
        filtered_data[hist_type]['not_mutated']
    ])

chi2_stat, p_value, dof, expected = stats.chi2_contingency(observed_matrix)[:4]

result = {
    'chi_square_statistic': chi2_stat,
    'p_value': p_value,
    'degrees_of_freedom': dof,
    'filtered_categories': len(filtered_data),
    'total_patients_analyzed': grand_total,
    'cdh1_mutated_patients': col_totals['mutated'],
    'contingency_table': filtered_data
}

print('__RESULT__:')
print(json.dumps(result, indent=2))"}

