    mutation_data = json.load(f)

# Extract BRCA female patients with known histological types
patient_info = []
for record in clinical_data:
    desc = record.get('Patient_description', '')
    hist_type = record.get('histological_type', '')
    tcga_match = re.search(r'(TCGA-\w+-\w+)', desc)
    if tcga_match:
        barcode = tcga_match.group(1)
        if hist_type and hist_type != 'None' and hist_type.strip():
            patient_info.append({'ParticipantBarcode': barcode, 'histological_type': hist_type})

# Get CDH1 mutated patients (PASS filter only)
cdh1_mutated = set()
for record in mutation_data:
    if record['FILTER'] == 'PASS':
        cdh1_mutated.add(record['ParticipantBarcode'])

# Build contingency table for histological types
contingency = {}
for patient in patient_info:
    hist = patient['histological_type']
    barcode = patient['ParticipantBarcode']
    if hist not in contingency:
        contingency[hist] = {'mutated': 0, 'not_mutated': 0}
    if barcode in cdh1_mutated:
        contingency[hist]['mutated'] += 1
    else:
        contingency[hist]['not_mutated'] += 1

# Filter categories with marginal totals <= 10
filtered_contingency = {k: v for k, v in contingency.items() if v['mutated'] + v['not_mutated'] > 10}

# Build observed matrix and run chi-square test
observed = []
category_names = []
for hist, counts in filtered_contingency.items():
    observed.append([counts['mutated'], counts['not_mutated']])
    category_names.append(hist)

chi2_stat = None
p_value = None
dof = None

if len(observed) >= 2:
    chi2_stat, p_value, dof, _ = stats.chi2_contingency(observed)
    result = {
        'chi_square_statistic': chi2_stat,
        'p_value': p_value,
        'degrees_of_freedom': dof,
        'filtered_categories': len(category_names),
        'total_patients': sum(sum(row) for row in observed),
        'cdh1_mutated_patients': sum(row[0] for row in observed),
        'category_names': category_names
    }
