            expected = (row_totals[h] * col_totals[status]) / grand_total
            expected_table[h][status] = expected

            # Add to chi-square statistic
            observed = filtered[h][status]
            chi_square += ((observed - expected) ** 2) / expected

    # Degrees of freedom = (rows - 1) * (columns - 1)
